// Display the player's score
function drawScore() {
  ctx.fillStyle = 'black';
  ctx.font = '20px Arial';
  ctx.fillText(`Score: ${score}`, 10, 20);
}

// Update game entities
function updateEntities() {
  // Update player
  player.update();

  // Update all bullets
  bullets.forEach(bullet => bullet.update());

  // Update all enemies
  enemies.forEach((enemy, index) => {
    enemy.update();
    // Check if enemy is off screen
    if (enemy.x + enemy.width < 0) {
      enemies.splice(index, 1);
    }
  });
}

// Draw game entities
function drawEntities() {
  // Draw player
  player.draw();

  // Draw all bullets
  bullets.forEach(bullet => bullet.draw());

  // Draw all enemies
  enemies.forEach(enemy => enemy.draw());

  // Draw the score
  drawScore();
}

// Main game loop
function gameLoop() {
  ctx.clearRect(0, 0, canvas.width, canvas.height); // Clears the canvas

  // Handle inputs and update game entities
  handleInput();
  updateEntities();

  // Draw all game entities
  drawEntities();

  // Check for collisions and game over condition
  checkCollisions();
  checkGameOver();

  // Enemy generation
  if (enemyTimer > enemyInterval) {
    createEnemy();
    enemyTimer = 0;
  } else {
    enemyTimer++;
  }

  // Repeat the loop
  if (!gameOver) {
    requestAnimationFrame(gameLoop);
  } else {
    displayGameOver();
  }
}

// Function to display game over message
function displayGameOver() {
  ctx.fillStyle = 'black';
  ctx.font = '36px Arial';
  ctx.fillText('Game Over', canvas.width / 2 - 100, canvas.height / 2);
  ctx.font = '24px Arial';
  ctx.fillText('Press R to Restart', canvas.width / 2 - 100, canvas.height / 2 + 50);
  window.addEventListener('keydown', restartGame);
}

// Restart game function
function restartGame(e) {
  if (e.key.toLowerCase() === 'r') {
    // Reset all game variables
    gameOver = false;
    score = 0;
    player = new Player(100, canvas.height / 2 - 25);
    bullets = [];
    enemies = [];
    enemyTimer = 0;

    // Reinitialize game loop
    update();
    window.removeEventListener('keydown', restartGame);
  }
}

// Initial call to start game loop
gameLoop();
